import React, { useEffect, useState } from 'react';
import './UIDSILoginPage.css';
import { TelemetryCollector } from './telemetryCollector';
import { InteractionTracker } from "./interactionTracker";
import { EnvironmentFingerprint } from './envFingerprint';

interface CaptchaChallenge {
  id: string;
  image: string;
  text: string;
  difficulty: 'easy' | 'medium' | 'hard';
}

interface BotDetectionResult {
  risk_score: number;
  is_bot: boolean;
  recommended_action: string;
}

const UIDSILoginPage: React.FC = () => {
  const [aadharInput, setAadharInput] = useState('');
  const [captchaInput, setCaptchaInput] = useState('');
  const [captchaText, setCaptchaText] = useState('bbfd68');
  const [loginAttempts, setLoginAttempts] = useState(0);
  const [isLocked, setIsLocked] = useState(false);
  const [botDetectionResult, setBotDetectionResult] = useState<BotDetectionResult | null>(null);
  const [isChecking, setIsChecking] = useState(false);
  const [errorMessage, setErrorMessage] = useState('');
  const [successMessage, setSuccessMessage] = useState('');
  const [telemetryCollected, setTelemetryCollected] = useState(false);

  // Collect telemetry on mount
  useEffect(() => {
    const collectTelemetry = async () => {
      const telemetryCollector = new TelemetryCollector();
      const interactionTracker = new InteractionTracker();

      // Start tracking immediately
      console.log('Telemetry collection started...');

      // Collect data after user interactions
      setTimeout(() => {
        setTelemetryCollected(true);
      }, 2000);
    };

    collectTelemetry();
  }, []);

  // Generate random CAPTCHA
  const generateCaptcha = () => {
    const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
    let captcha = '';
    for (let i = 0; i < 6; i++) {
      captcha += chars.charAt(Math.floor(Math.random() * chars.length));
    }
    setCaptchaText(captcha);
  };

  // Verify CAPTCHA
  const verifyCaptcha = () => {
    if (captchaInput.toLowerCase() === captchaText.toLowerCase()) {
      return true;
    }
    return false;
  };

  // Check for bot using our ML model
  const checkIfBot = async (): Promise<BotDetectionResult> => {
    setIsChecking(true);
    try {
      const telemetryCollector = new TelemetryCollector();
      const interactionTracker = new InteractionTracker();

      const deviceFp = telemetryCollector.captureDeviceFingerprint();
      const interactions = interactionTracker.getAllSignals();
      const headlessCheck = EnvironmentFingerprint.detectHeadlessIndicators();
      const jitter = await (EnvironmentFingerprint.measureEventLoopJitter() as Promise<number>);
      const payload = {
        telemetry: {
          device: deviceFp,
          mouse: interactions?.mouse || {},
          keyboard: interactions?.keyboard || {},
          timing: {
            event_loop_jitter: jitter
          }
        },
        session_id: 'uidai-' + Date.now()
      };

      const response = await fetch('http://localhost:8000/api/predict', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify(payload)
      });

      if (!response.ok) {
        throw new Error('Bot detection API failed');
      }

      const result = await response.json();

      const botResult: BotDetectionResult = {
        risk_score: result.risk_score,
        is_bot: result.risk_score > 60,
        recommended_action: result.recommended_action
      };

      setBotDetectionResult(botResult);
      return botResult;
    } catch (error) {
      console.error('Bot detection error:', error);
      return {
        risk_score: 50,
        is_bot: false,
        recommended_action: 'SOFT_CHALLENGE'
      };
    } finally {
      setIsChecking(false);
    }
  };

  // Replace the handleLogin function with this:

const handleLogin = async () => {
  setErrorMessage('');
  setSuccessMessage('');

  // Check if locked
  if (isLocked) {
    setErrorMessage('Too many attempts. Please try again later.');
    return;
  }

  // Check admin credentials FIRST (before bot check)
  if (aadharInput === '37775631' && captchaInput === 'G8') {
    setSuccessMessage('✅ Admin access granted! Opening dashboard...');
    // Open admin in new tab
    setTimeout(() => {
      window.open('/admin-dashboard', '_blank', 'width=1400,height=900');
    }, 500);
    // Reset form
    setAadharInput('');
    setCaptchaInput('');
    generateCaptcha();
    return;
  }

  // For non-admin: Validate Aadhar
  if (!aadharInput || aadharInput.length !== 12) {
    setErrorMessage('Please enter a valid 12-digit Aadhar number');
    return;
  }

  // Check for bot
  const botResult = await checkIfBot();

  if (botResult.is_bot) {
    setErrorMessage('🚫 Bot detected! Please try again with natural interactions.');
    setLoginAttempts(prev => prev + 1);
    if (loginAttempts >= 3) {
      setIsLocked(true);
    }
    return;
  }

  // Verify CAPTCHA
  if (!verifyCaptcha()) {
    setErrorMessage('❌ Incorrect CAPTCHA. Please try again.');
    setLoginAttempts(prev => prev + 1);
    generateCaptcha();
    if (loginAttempts >= 3) {
      setIsLocked(true);
    }
    return;
  }

  // Success for regular user
  setSuccessMessage('✅ Bot detection passed! Proceeding with OTP...');
  setTimeout(() => {
    alert('Verification successful! Risk Score: ' + botResult.risk_score);
  }, 1000);

  // Reset
  setAadharInput('');
  setCaptchaInput('');
  generateCaptcha();
};

  // Handle refresh CAPTCHA
  const handleRefreshCaptcha = () => {
    generateCaptcha();
    setCaptchaInput('');
  };

  return (
    <div className="uidai-container">
      <header className="uidai-header">
        <div className="header-content">
          <div className="logo-section">
            <img src="data:image/svg+xml,%3Csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 100 100'%3E%3Ccircle cx='50' cy='50' r='45' fill='%234C63B6'/%3E%3Ctext x='50' y='60' font-size='40' fill='white' text-anchor='middle' font-weight='bold'%3Eㄴ%3C/text%3E%3C/svg%3E" alt="UIDAI" className="logo" />
            <div className="header-text">
              <h1>Unique Identification Authority of India</h1>
              <p className="subtitle">myAadhaar - Passive Bot Detection System</p>
            </div>
          </div>
          <img src="data:image/svg+xml,%3Csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 100 100'%3E%3Ccircle cx='50' cy='50' r='45' fill='%23FF9B00'/%3E%3Ctext x='50' y='60' font-size='30' fill='white' text-anchor='middle' font-weight='bold'%3EA%3C/text%3E%3C/svg%3E" alt="Aadhaar" className="aadhaar-logo" />
        </div>
      </header>

      <main className="uidai-main">
        <div className="login-container">
          <div className="login-card">
            <h2 className="card-title">eAadhaar Download / Verification</h2>
            <p className="card-subtitle">Select 12 digit Aadhar Number</p>

            {botDetectionResult && (
              <div className={`bot-detection-alert ${botDetectionResult.is_bot ? 'alert-danger' : 'alert-success'}`}>
                <p><strong>Risk Assessment:</strong> {botDetectionResult.risk_score}/100</p>
                <p><strong>Status:</strong> {botDetectionResult.is_bot ? '⚠️ Bot Detected' : '✅ Human Verified'}</p>
              </div>
            )}

            {errorMessage && (
              <div className="alert alert-error">
                {errorMessage}
              </div>
            )}

            {successMessage && (
              <div className="alert alert-success">
                {successMessage}
              </div>
            )}

            <form onSubmit={(e) => { e.preventDefault(); handleLogin(); }} className="login-form">
              <div className="form-group">
                <label htmlFor="aadhar">Enter Aadhar Number</label>
                <input
                  id="aadhar"
                  type="text"
                  placeholder="Enter 12 digit Aadhar Number"
                  value={aadharInput}
                  onChange={(e) => setAadharInput(e.target.value.replace(/\D/g, '').slice(0, 12))}
                  maxLength={12}
                  disabled={isLocked}
                  className="form-input"
                />
              </div>

              <div className="form-group">
                <label htmlFor="captcha">Enter Captcha</label>
                <div className="captcha-container">
                  <div className="captcha-image">
                    <span className="captcha-text">{captchaText}</span>
                  </div>
                  <button
                    type="button"
                    className="captcha-refresh"
                    onClick={handleRefreshCaptcha}
                    title="Refresh CAPTCHA"
                  >
                    🔄
                  </button>
                </div>
                <input
                  id="captcha"
                  type="text"
                  placeholder="Enter Captcha"
                  value={captchaInput}
                  onChange={(e) => setCaptchaInput(e.target.value)}
                  disabled={isLocked}
                  className="form-input"
                />
              </div>

              <button
                type="submit"
                className={`submit-button ${isLocked ? 'disabled' : ''}`}
                disabled={isLocked || isChecking}
              >
                {isChecking ? '⏳ Checking...' : '📤 Send OTP'}
              </button>

              {isLocked && (
                <p className="locked-message">🔒 Too many attempts. Please try again later.</p>
              )}

              {loginAttempts > 0 && loginAttempts < 3 && (
                <p className="attempts-warning">⚠️ Attempts remaining: {3 - loginAttempts}</p>
              )}
            </form>

            <div className="faq-section">
              <h3>Frequently Asked Questions</h3>
              <details className="faq-item">
                <summary>What is e-Aadhar?</summary>
                <p>e-Aadhar is an electronic version of your Aadhar document that can be downloaded and printed.</p>
              </details>
              <details className="faq-item">
                <summary>What is this Passive Bot Detection?</summary>
                <p>Our system silently analyzes your behavior to detect if you're a real human or an automated bot, protecting your identity.</p>
              </details>
              <details className="faq-item">
                <summary>Is my data safe?</summary>
                <p>Yes! We only collect behavioral signals and don't store personal information. All data is encrypted and compliant with privacy laws.</p>
              </details>
            </div>
          </div>

          {/* Telemetry Display */}
          <div className="telemetry-info">
            <h3>🔐 Passive Bot Detection Active</h3>
            <p className="telemetry-status">
              {telemetryCollected ? '✅ Telemetry Collected' : '⏳ Collecting telemetry...'}
            </p>
            <p className="telemetry-note">
              Moving your mouse and typing naturally helps us verify you're human.
            </p>
          </div>
        </div>
      </main>

      <footer className="uidai-footer">
        <p>&copy; 2026 Unique Identification Authority of India. All rights reserved.</p>
      </footer>
    </div>
  );
};

export default UIDSILoginPage;
